def length_normalized_log_odds(log_p: torch.Tensor, lengths: torch.Tensor) -> torch.Tensor:
    """Normalize log-prob by length before odds, then compute log-odds."""
    norm_log_p = log_p / lengths.float().clamp(min=1)
    # Cast to float32 for precision
    norm_log_p = norm_log_p.float()
    return norm_log_p - torch.log(-torch.expm1(norm_log_p))
